    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'homeassistant/components/sonos/media_player.py': '"""Support to interface with Sonos players."""\n\nfrom __future__ import annotations\n\nimport datetime\nfrom functools import partial\nimport logging\nfrom typing import TYPE_CHECKING, Any\n\nfrom soco import SoCo, alarms\nfrom soco.core import (\n    MUSIC_SRC_LINE_IN,\n    MUSIC_SRC_RADIO,\n    PLAY_MODE_BY_MEANING,\n    PLAY_MODES,\n)\nfrom soco.data_structures import DidlFavorite, DidlMusicTrack\nfrom soco.ms_data_structures import MusicServiceItem\nfrom sonos_websocket.exception import SonosWebsocketError\n\nfrom homeassistant.components import media_source, spotify\nfrom homeassistant.components.media_player import (\n    ATTR_INPUT_SOURCE,\n    ATTR_MEDIA_ALBUM_NAME,\n    ATTR_MEDIA_ANNOUNCE,\n    ATTR_MEDIA_ARTIST,\n    ATTR_MEDIA_CONTENT_ID,\n    ATTR_MEDIA_ENQUEUE,\n    ATTR_MEDIA_TITLE,\n    BrowseMedia,\n    MediaPlayerDeviceClass,\n    MediaPlayerEnqueue,\n    MediaPlayerEntity,\n    MediaPlayerEntityFeature,\n    MediaPlayerState,\n    MediaType,\n    RepeatMode,\n    async_process_play_media_url,\n)\nfrom homeassistant.components.plex import PLEX_URI_SCHEME\nfrom homeassistant.components.plex.services import process_plex_payload\nfrom homeassistant.core import HomeAssistant, callback\nfrom homeassistant.exceptions import HomeAssistantError, ServiceValidationError\nfrom homeassistant.helpers import entity_registry as er\nfrom homeassistant.helpers.dispatcher import async_dispatcher_connect\nfrom homeassistant.helpers.entity_platform import AddConfigEntryEntitiesCallback\nfrom homeassistant.helpers.event import async_call_later\n\nfrom . import media_browser\nfrom .const import (\n    ATTR_QUEUE_POSITION,\n    DOMAIN,\n    MEDIA_TYPE_DIRECTORY,\n    MEDIA_TYPES_TO_SONOS,\n    MODELS_LINEIN_AND_TV,\n    MODELS_LINEIN_ONLY,\n    MODELS_TV_ONLY,\n    PLAYABLE_MEDIA_TYPES,\n    SONOS_CREATE_MEDIA_PLAYER,\n    SONOS_MEDIA_UPDATED,\n    SONOS_STATE_PLAYING,\n    SONOS_STATE_TRANSITIONING,\n    SOURCE_LINEIN,\n    SOURCE_TV,\n)\nfrom .entity import SonosEntity\nfrom .helpers import UnjoinData, soco_error\nfrom .speaker import SonosMedia, SonosSpeaker\n\nif TYPE_CHECKING:\n    from .helpers import SonosConfigEntry\n\n_LOGGER = logging.getLogger(__name__)\n\nLONG_SERVICE_TIMEOUT = 30.0\nUNJOIN_SERVICE_TIMEOUT = 0.1\nVOLUME_INCREMENT = 2\n\nREPEAT_TO_SONOS = {\n    RepeatMode.OFF: False,\n    RepeatMode.ALL: True,\n    RepeatMode.ONE: "ONE",\n}\n\nSONOS_TO_REPEAT = {meaning: mode for mode, meaning in REPEAT_TO_SONOS.items()}\n\nUPNP_ERRORS_TO_IGNORE = ["701", "711", "712"]\nANNOUNCE_NOT_SUPPORTED_ERRORS: list[str] = ["globalError"]\n\n\nasync def async_setup_entry(\n    hass: HomeAssistant,\n    config_entry: SonosConfigEntry,\n    async_add_entities: AddConfigEntryEntitiesCallback,\n) -> None:\n    """Set up Sonos from a config entry."""\n\n    @callback\n    def async_create_entities(speaker: SonosSpeaker) -> None:\n        """Handle device discovery and create entities."""\n        _LOGGER.debug("Creating media_player on %s", speaker.zone_name)\n        async_add_entities([SonosMediaPlayerEntity(speaker, config_entry)])\n\n    config_entry.async_on_unload(\n        async_dispatcher_connect(hass, SONOS_CREATE_MEDIA_PLAYER, async_create_entities)\n    )\n\n\nclass SonosMediaPlayerEntity(SonosEntity, MediaPlayerEntity):\n    """Representation of a Sonos entity."""\n\n    _attr_name = None\n    _attr_supported_features = (\n        MediaPlayerEntityFeature.BROWSE_MEDIA\n        | MediaPlayerEntityFeature.CLEAR_PLAYLIST\n        | MediaPlayerEntityFeature.GROUPING\n        | MediaPlayerEntityFeature.MEDIA_ANNOUNCE\n        | MediaPlayerEntityFeature.MEDIA_ENQUEUE\n        | MediaPlayerEntityFeature.NEXT_TRACK\n        | MediaPlayerEntityFeature.PAUSE\n        | MediaPlayerEntityFeature.PLAY\n        | MediaPlayerEntityFeature.PLAY_MEDIA\n        | MediaPlayerEntityFeature.PREVIOUS_TRACK\n        | MediaPlayerEntityFeature.REPEAT_SET\n        | MediaPlayerEntityFeature.SEEK\n        | MediaPlayerEntityFeature.SELECT_SOURCE\n        | MediaPlayerEntityFeature.SHUFFLE_SET\n        | MediaPlayerEntityFeature.STOP\n        | MediaPlayerEntityFeature.VOLUME_MUTE\n        | MediaPlayerEntityFeature.VOLUME_SET\n    )\n    _attr_media_content_type = MediaType.MUSIC\n    _attr_device_class = MediaPlayerDeviceClass.SPEAKER\n\n    def __init__(self, speaker: SonosSpeaker, config_entry: SonosConfigEntry) -> None:\n        """Initialize the media player entity."""\n        super().__init__(speaker, config_entry)\n        self._attr_unique_id = self.soco.uid\n\n    async def async_added_to_hass(self) -> None:\n        """Handle common setup when added to hass."""\n        await super().async_added_to_hass()\n        self.async_on_remove(\n            async_dispatcher_connect(\n                self.hass,\n                SONOS_MEDIA_UPDATED,\n                self.async_write_media_state,\n            )\n        )\n\n    @callback\n    def async_write_media_state(self, uid: str) -> None:\n        """Write media state if the provided UID is coordinator of this speaker."""\n        if self.coordinator.uid == uid:\n            self.async_write_ha_state()\n\n    @property\n    def available(self) -> bool:\n        """Return if the media_player is available."""\n        return (\n            self.speaker.available\n            and bool(self.speaker.sonos_group_entities)\n            and self.media.playback_status is not None\n        )\n\n    @property\n    def coordinator(self) -> SonosSpeaker:\n        """Return the current coordinator SonosSpeaker."""\n        return self.speaker.coordinator or self.speaker\n\n    @property\n    def group_members(self) -> list[str] | None:\n        """List of entity_ids which are currently grouped together."""\n        return self.speaker.sonos_group_entities\n\n    def __hash__(self) -> int:\n        """Return a hash of self."""\n        return hash(self.unique_id)\n\n    @property\n    def state(self) -> MediaPlayerState:\n        """Return the state of the entity."""\n        if self.media.playback_status in (\n            "PAUSED_PLAYBACK",\n            "STOPPED",\n        ):\n            # Sonos can consider itself "paused" but without having media loaded\n            # (happens if playing Spotify and via Spotify app\n            # you pick another device to play on)\n            if self.media.title is None:\n                return MediaPlayerState.IDLE\n            return MediaPlayerState.PAUSED\n        if self.media.playback_status in (\n            SONOS_STATE_PLAYING,\n            SONOS_STATE_TRANSITIONING,\n        ):\n            return MediaPlayerState.PLAYING\n        return MediaPlayerState.IDLE\n\n    async def _async_fallback_poll(self) -> None:\n        """Retrieve latest state by polling."""\n        favorites = self.config_entry.runtime_data.favorites[self.speaker.household_id]\n        assert favorites.async_poll\n        await favorites.async_poll()\n        await self.hass.async_add_executor_job(self._update)\n\n    def _update(self) -> None:\n        """Retrieve latest state by polling."""\n        self.speaker.update_groups()\n        self.speaker.update_volume()\n        if self.speaker.is_coordinator:\n            self.media.poll_media()\n\n    @property\n    def volume_level(self) -> float | None:\n        """Volume level of the media player (0..1)."""\n        return self.speaker.volume and self.speaker.volume / 100\n\n    @property\n    def is_volume_muted(self) -> bool | None:\n        """Return true if volume is muted."""\n        return self.speaker.muted\n\n    @property\n    def shuffle(self) -> bool | None:\n        """Shuffling state."""\n        return PLAY_MODES[self.media.play_mode][0]\n\n    @property\n    def repeat(self) -> RepeatMode | None:\n        """Return current repeat mode."""\n        sonos_repeat = PLAY_MODES[self.media.play_mode][1]\n        return SONOS_TO_REPEAT[sonos_repeat]\n\n    @property\n    def media(self) -> SonosMedia:\n        """Return the SonosMedia object from the coordinator speaker."""\n        return self.coordinator.media\n\n    @property\n    def media_content_id(self) -> str | None:\n        """Content id of current playing media."""\n        return self.media.uri\n\n    @property\n    def media_duration(self) -> int | None:\n        """Duration of current playing media in seconds."""\n        return int(self.media.duration) if self.media.duration else None\n\n    @property\n    def media_position(self) -> int | None:\n        """Position of current playing media in seconds."""\n        return self.media.position\n\n    @property\n    def media_position_updated_at(self) -> datetime.datetime | None:\n        """When was the position of the current playing media valid."""\n        return self.media.position_updated_at\n\n    @property\n    def media_image_url(self) -> str | None:\n        """Image url of current playing media."""\n        return self.media.image_url or None\n\n    @property\n    def media_channel(self) -> str | None:\n        """Channel currently playing."""\n        return self.media.channel or None\n\n    @property\n    def media_playlist(self) -> str | None:\n        """Title of playlist currently playing."""\n        return self.media.playlist_name\n\n    @property\n    def media_artist(self) -> str | None:\n        """Artist of current playing media, music track only."""\n        return self.media.artist or None\n\n    @property\n    def media_album_name(self) -> str | None:\n        """Album name of current playing media, music track only."""\n        return self.media.album_name or None\n\n    @property\n    def media_title(self) -> str | None:\n        """Title of current playing media."""\n        return self.media.title or None\n\n    @property\n    def source(self) -> str | None:\n        """Name of the current input source."""\n        return self.media.source_name or None\n\n    @soco_error()\n    def volume_up(self) -> None:\n        """Volume up media player."""\n        self.soco.volume += VOLUME_INCREMENT\n\n    @soco_error()\n    def volume_down(self) -> None:\n        """Volume down media player."""\n        self.soco.volume -= VOLUME_INCREMENT\n\n    @soco_error()\n    def set_volume_level(self, volume: float) -> None:\n        """Set volume level, range 0..1."""\n        self.soco.volume = int(round(volume * 100))\n\n    @soco_error(UPNP_ERRORS_TO_IGNORE)\n    def set_shuffle(self, shuffle: bool) -> None:\n        """Enable/Disable shuffle mode."""\n        sonos_shuffle = shuffle\n        sonos_repeat = PLAY_MODES[self.media.play_mode][1]\n        self.coordinator.soco.play_mode = PLAY_MODE_BY_MEANING[\n            (sonos_shuffle, sonos_repeat)\n        ]\n\n    @soco_error(UPNP_ERRORS_TO_IGNORE)\n    def set_repeat(self, repeat: RepeatMode) -> None:\n        """Set repeat mode."""\n        sonos_shuffle = PLAY_MODES[self.media.play_mode][0]\n        sonos_repeat = REPEAT_TO_SONOS[repeat]\n        self.coordinator.soco.play_mode = PLAY_MODE_BY_MEANING[\n            (sonos_shuffle, sonos_repeat)\n        ]\n\n    @soco_error()\n    def mute_volume(self, mute: bool) -> None:\n        """Mute (true) or unmute (false) media player."""\n        self.soco.mute = mute\n\n    @soco_error()\n    def select_source(self, source: str) -> None:\n        """Select input source."""\n        soco = self.coordinator.soco\n        if source == SOURCE_LINEIN:\n            soco.switch_to_line_in()\n            return\n\n        if source == SOURCE_TV:\n            soco.switch_to_tv()\n            return\n\n        self._play_favorite_by_name(source)\n\n    def _play_favorite_by_name(self, name: str) -> None:\n        """Play a favorite by name."""\n        fav = [fav for fav in self.speaker.favorites if fav.title == name]\n\n        if len(fav) != 1:\n            raise ServiceValidationError(\n                translation_domain=DOMAIN,\n                translation_key="invalid_favorite",\n                translation_placeholders={\n                    "name": name,\n                },\n            )\n\n        src = fav.pop()\n        self._play_favorite(src)\n\n    def _play_favorite(self, favorite: DidlFavorite) -> None:\n        """Play a favorite."""\n        uri = favorite.reference.get_uri()\n        soco = self.coordinator.soco\n        if (\n            soco.music_source_from_uri(uri)\n            in [\n                MUSIC_SRC_RADIO,\n                MUSIC_SRC_LINE_IN,\n            ]\n            or favorite.reference.item_class == "object.item.audioItem.audioBook"\n        ):\n            soco.play_uri(\n                uri,\n                title=favorite.title,\n                meta=favorite.resource_meta_data,\n                timeout=LONG_SERVICE_TIMEOUT,\n            )\n        else:\n            soco.clear_queue()\n            soco.add_to_queue(favorite.reference, timeout=LONG_SERVICE_TIMEOUT)\n            soco.play_from_queue(0)\n\n    @property\n    def source_list(self) -> list[str]:\n        """List of available input sources."""\n        model = self.coordinator.model_name.split()[-1].upper()\n        if model in MODELS_LINEIN_ONLY:\n            return [SOURCE_LINEIN]\n        if model in MODELS_TV_ONLY:\n            return [SOURCE_TV]\n        if model in MODELS_LINEIN_AND_TV:\n            return [SOURCE_LINEIN, SOURCE_TV]\n        return []\n\n    @soco_error(UPNP_ERRORS_TO_IGNORE)\n    def media_play(self) -> None:\n        """Send play command."""\n        self.coordinator.soco.play()\n\n    @soco_error(UPNP_ERRORS_TO_IGNORE)\n    def media_stop(self) -> None:\n        """Send stop command."""\n        self.coordinator.soco.stop()\n\n    @soco_error(UPNP_ERRORS_TO_IGNORE)\n    def media_pause(self) -> None:\n        """Send pause command."""\n        self.coordinator.soco.pause()\n\n    @soco_error(UPNP_ERRORS_TO_IGNORE)\n    def media_next_track(self) -> None:\n        """Send next track command."""\n        self.coordinator.soco.next()\n\n    @soco_error(UPNP_ERRORS_TO_IGNORE)\n    def media_previous_track(self) -> None:\n        """Send next track command."""\n        self.coordinator.soco.previous()\n\n    @soco_error(UPNP_ERRORS_TO_IGNORE)\n    def media_seek(self, position: float) -> None:\n        """Send seek command."""\n        self.coordinator.soco.seek(str(datetime.timedelta(seconds=int(position))))\n\n    @soco_error()\n    def clear_playlist(self) -> None:\n        """Clear players playlist."""\n        self.coordinator.soco.clear_queue()\n\n    async def async_play_media(\n        self, media_type: MediaType | str, media_id: str, **kwargs: Any\n    ) -> None:\n        """Send the play_media command to the media player.\n\n        If media_id is a Plex payload, attempt Plex->Sonos playback.\n\n        If media_id is an Apple Music, Deezer, Sonos, or Tidal share link,\n        attempt playback using the respective service.\n\n        If media_type is "playlist", media_id should be a Sonos\n        Playlist name.  Otherwise, media_id should be a URI.\n        """\n        is_radio = False\n\n        if media_source.is_media_source_id(media_id):\n            is_radio = media_id.startswith("media-source://radio_browser/")\n            media_type = MediaType.MUSIC\n            media = await media_source.async_resolve_media(\n                self.hass, media_id, self.entity_id\n            )\n            media_id = async_process_play_media_url(self.hass, media.url)\n\n        if kwargs.get(ATTR_MEDIA_ANNOUNCE):\n            volume = kwargs.get("extra", {}).get("volume")\n            _LOGGER.debug("Playing %s using websocket audioclip", media_id)\n            try:\n                assert self.speaker.websocket\n                response, _ = await self.speaker.websocket.play_clip(\n                    async_process_play_media_url(self.hass, media_id),\n                    volume=volume,\n                )\n            except SonosWebsocketError as exc:\n                raise HomeAssistantError(\n                    f"Error when calling Sonos websocket: {exc}"\n                ) from exc\n            if response.get("success"):\n                return\n            if response.get("type") in ANNOUNCE_NOT_SUPPORTED_ERRORS:\n                # If the speaker does not support announce do not raise and\n                # fall through to_play_media to play the clip directly.\n                _LOGGER.debug(\n                    "Speaker %s does not support announce, media_id %s response %s",\n                    self.speaker.zone_name,\n                    media_id,\n                    response,\n                )\n            else:\n                raise HomeAssistantError(\n                    translation_domain=DOMAIN,\n                    translation_key="announce_media_error",\n                    translation_placeholders={\n                        "media_id": media_id,\n                        "response": response,\n                    },\n                )\n\n        if spotify.is_spotify_media_type(media_type):\n            media_type = spotify.resolve_spotify_media_type(media_type)\n            media_id = spotify.spotify_uri_from_media_browser_url(media_id)\n\n        await self.hass.async_add_executor_job(\n            partial(self._play_media, media_type, media_id, is_radio, **kwargs)\n        )\n\n    @soco_error()\n    def _play_media(\n        self, media_type: MediaType | str, media_id: str, is_radio: bool, **kwargs: Any\n    ) -> None:\n        """Wrap sync calls to async_play_media."""\n        _LOGGER.debug("_play_media media_type %s media_id %s", media_type, media_id)\n        enqueue = kwargs.get(ATTR_MEDIA_ENQUEUE, MediaPlayerEnqueue.REPLACE)\n\n        if media_type == "favorite_item_id":\n            favorite = self.speaker.favorites.lookup_by_item_id(media_id)\n            if favorite is None:\n                raise ValueError(f"Missing favorite for media_id: {media_id}")\n            self._play_favorite(favorite)\n            return\n\n        soco = self.coordinator.soco\n        if media_id and media_id.startswith(PLEX_URI_SCHEME):\n            plex_plugin = self.speaker.plex_plugin\n            result = process_plex_payload(\n                self.hass, media_type, media_id, supports_playqueues=False\n            )\n            if result.shuffle:\n                self.set_shuffle(True)\n            if enqueue == MediaPlayerEnqueue.ADD:\n                plex_plugin.add_to_queue(result.media, timeout=LONG_SERVICE_TIMEOUT)\n            elif enqueue in (\n                MediaPlayerEnqueue.NEXT,\n                MediaPlayerEnqueue.PLAY,\n            ):\n                pos = (self.media.queue_position or 0) + 1\n                new_pos = plex_plugin.add_to_queue(\n                    result.media, position=pos, timeout=LONG_SERVICE_TIMEOUT\n                )\n                if enqueue == MediaPlayerEnqueue.PLAY:\n                    soco.play_from_queue(new_pos - 1)\n            elif enqueue == MediaPlayerEnqueue.REPLACE:\n                soco.clear_queue()\n                plex_plugin.add_to_queue(result.media, timeout=LONG_SERVICE_TIMEOUT)\n                soco.play_from_queue(0)\n            return\n\n        share_link = self.coordinator.share_link\n        if share_link.is_share_link(media_id):\n            if enqueue == MediaPlayerEnqueue.ADD:\n                share_link.add_share_link_to_queue(\n                    media_id, timeout=LONG_SERVICE_TIMEOUT\n                )\n            elif enqueue in (\n                MediaPlayerEnqueue.NEXT,\n                MediaPlayerEnqueue.PLAY,\n            ):\n                pos = (self.media.queue_position or 0) + 1\n                new_pos = share_link.add_share_link_to_queue(\n                    media_id, position=pos, timeout=LONG_SERVICE_TIMEOUT\n                )\n                if enqueue == MediaPlayerEnqueue.PLAY:\n                    soco.play_from_queue(new_pos - 1)\n            elif enqueue == MediaPlayerEnqueue.REPLACE:\n                soco.clear_queue()\n                share_link.add_share_link_to_queue(\n                    media_id, timeout=LONG_SERVICE_TIMEOUT\n                )\n                soco.play_from_queue(0)\n        elif media_type == MEDIA_TYPE_DIRECTORY:\n            self._play_media_directory(\n                soco=soco, media_type=media_type, media_id=media_id, enqueue=enqueue\n            )\n        elif media_type in {MediaType.MUSIC, MediaType.TRACK}:\n            # If media ID is a relative URL, we serve it from HA.\n            media_id = async_process_play_media_url(self.hass, media_id)\n\n            if enqueue == MediaPlayerEnqueue.ADD:\n                soco.add_uri_to_queue(media_id, timeout=LONG_SERVICE_TIMEOUT)\n            elif enqueue in (\n                MediaPlayerEnqueue.NEXT,\n                MediaPlayerEnqueue.PLAY,\n            ):\n                pos = (self.media.queue_position or 0) + 1\n                new_pos = soco.add_uri_to_queue(\n                    media_id, position=pos, timeout=LONG_SERVICE_TIMEOUT\n                )\n                if enqueue == MediaPlayerEnqueue.PLAY:\n                    soco.play_from_queue(new_pos - 1)\n            elif enqueue == MediaPlayerEnqueue.REPLACE:\n                soco.play_uri(media_id, force_radio=is_radio)\n        elif media_type == MediaType.PLAYLIST:\n            if media_id.startswith("S:"):\n                playlist = media_browser.get_media(\n                    self.media.library, media_id, media_type\n                )\n            else:\n                playlists = soco.get_sonos_playlists(complete_result=True)\n                playlist = next((p for p in playlists if p.title == media_id), None)\n            if not playlist:\n                raise ServiceValidationError(\n                    translation_domain=DOMAIN,\n                    translation_key="invalid_sonos_playlist",\n                    translation_placeholders={\n                        "name": media_id,\n                    },\n                )\n            soco.clear_queue()\n            soco.add_to_queue(playlist, timeout=LONG_SERVICE_TIMEOUT)\n            soco.play_from_queue(0)\n        elif media_type in PLAYABLE_MEDIA_TYPES:\n            item = media_browser.get_media(self.media.library, media_id, media_type)\n            if not item:\n                raise ServiceValidationError(\n                    translation_domain=DOMAIN,\n                    translation_key="invalid_media",\n                    translation_placeholders={\n                        "media_id": media_id,\n                    },\n                )\n            self._play_media_queue(soco, item, enqueue)\n        else:\n            raise ServiceValidationError(\n                translation_domain=DOMAIN,\n                translation_key="invalid_content_type",\n                translation_placeholders={\n                    "media_type": media_type,\n                },\n            )\n\n    def _play_media_queue(\n        self, soco: SoCo, item: MusicServiceItem, enqueue: MediaPlayerEnqueue\n    ):\n        """Manage adding, replacing, playing items onto the sonos queue."""\n        _LOGGER.debug(\n            "_play_media_queue item_id [%s] title [%s] enqueue [%s]",\n            item.item_id,\n            item.title,\n            enqueue,\n        )\n        if enqueue == MediaPlayerEnqueue.REPLACE:\n            soco.clear_queue()\n\n        if enqueue in (MediaPlayerEnqueue.ADD, MediaPlayerEnqueue.REPLACE):\n            soco.add_to_queue(item, timeout=LONG_SERVICE_TIMEOUT)\n            if enqueue == MediaPlayerEnqueue.REPLACE:\n                soco.play_from_queue(0)\n        else:\n            pos = (self.media.queue_position or 0) + 1\n            new_pos = soco.add_to_queue(\n                item, position=pos, timeout=LONG_SERVICE_TIMEOUT\n            )\n            if enqueue == MediaPlayerEnqueue.PLAY:\n                soco.play_from_queue(new_pos - 1)\n\n    def _play_media_directory(\n        self,\n        soco: SoCo,\n        media_type: MediaType | str,\n        media_id: str,\n        enqueue: MediaPlayerEnqueue,\n    ):\n        """Play a directory from a music library share."""\n        item = media_browser.get_media(self.media.library, media_id, media_type)\n        if not item:\n            raise ServiceValidationError(\n                translation_domain=DOMAIN,\n                translation_key="invalid_media",\n                translation_placeholders={\n                    "media_id": media_id,\n                },\n            )\n        self._play_media_queue(soco, item, enqueue)\n\n    @soco_error()\n    def set_sleep_timer(self, sleep_time: int) -> None:\n        """Set the timer on the player."""\n        self.coordinator.soco.set_sleep_timer(sleep_time)\n\n    @soco_error()\n    def clear_sleep_timer(self) -> None:\n        """Clear the timer on the player."""\n        self.coordinator.soco.set_sleep_timer(None)\n\n    @soco_error()\n    def set_alarm(\n        self,\n        alarm_id: int,\n        time: datetime.datetime | None = None,\n        volume: float | None = None,\n        enabled: bool | None = None,\n        include_linked_zones: bool | None = None,\n    ) -> None:\n        """Set the alarm clock on the player."""\n        alarm: alarms.Alarm | None = None\n        for one_alarm in alarms.get_alarms(self.coordinator.soco):\n            if one_alarm.alarm_id == str(alarm_id):\n                alarm = one_alarm\n        if alarm is None:\n            raise ServiceValidationError(\n                translation_domain=DOMAIN,\n                translation_key="invalid_alarm_id",\n                translation_placeholders={\n                    "alarm_id": str(alarm_id),\n                },\n            )\n        if time is not None:\n            alarm.start_time = time\n        if volume is not None:\n            alarm.volume = int(volume * 100)\n        if enabled is not None:\n            alarm.enabled = enabled\n        if include_linked_zones is not None:\n            alarm.include_linked_zones = include_linked_zones\n        alarm.save()\n\n    @soco_error()\n    def play_queue(self, queue_position: int = 0) -> None:\n        """Start playing the queue."""\n        self.soco.play_from_queue(queue_position)\n\n    @soco_error()\n    def remove_from_queue(self, queue_position: int = 0) -> None:\n        """Remove item from the queue."""\n        self.coordinator.soco.remove_from_queue(queue_position)\n\n    @soco_error()\n    def get_queue(self) -> list[dict]:\n        """Get the queue."""\n        queue: list[DidlMusicTrack] = self.coordinator.soco.get_queue(max_items=0)\n        return [\n            {\n                ATTR_MEDIA_TITLE: getattr(track, "title", None),\n                ATTR_MEDIA_ALBUM_NAME: getattr(track, "album", None),\n                ATTR_MEDIA_ARTIST: getattr(track, "creator", None),\n                ATTR_MEDIA_CONTENT_ID: track.get_uri(),\n            }\n            for track in queue\n        ]\n\n    @property\n    def extra_state_attributes(self) -> dict[str, Any]:\n        """Return entity specific state attributes."""\n        attributes: dict[str, Any] = {}\n\n        if self.media.queue_position is not None:\n            attributes[ATTR_QUEUE_POSITION] = self.media.queue_position\n\n        if self.media.queue_size:\n            attributes["queue_size"] = self.media.queue_size\n\n        if self.source:\n            attributes[ATTR_INPUT_SOURCE] = self.source\n\n        return attributes\n\n    async def async_get_browse_image(\n        self,\n        media_content_type: MediaType | str,\n        media_content_id: str,\n        media_image_id: str | None = None,\n    ) -> tuple[bytes | None, str | None]:\n        """Fetch media browser image to serve via proxy."""\n        if (\n            media_content_type in {MediaType.ALBUM, MediaType.ARTIST}\n            and media_content_id\n        ):\n            item = await self.hass.async_add_executor_job(\n                media_browser.get_media,\n                self.media.library,\n                media_content_id,\n                MEDIA_TYPES_TO_SONOS[media_content_type],\n            )\n            if image_url := getattr(item, "album_art_uri", None):\n                return await self._async_fetch_image(image_url)\n\n        return (None, None)\n\n    async def async_browse_media(\n        self,\n        media_content_type: MediaType | str | None = None,\n        media_content_id: str | None = None,\n    ) -> BrowseMedia:\n        """Implement the websocket media browsing helper."""\n        return await media_browser.async_browse_media(\n            self.hass,\n            self.speaker,\n            self.media,\n            self.get_browse_image_url,\n            media_content_id,\n            media_content_type,\n        )\n\n    async def async_join_players(self, group_members: list[str]) -> None:\n        """Join `group_members` as a player group with the current player."""\n        speakers = []\n\n        entity_registry = er.async_get(self.hass)\n        for entity_id in group_members:\n            if not (entity_reg_entry := entity_registry.async_get(entity_id)):\n                raise HomeAssistantError(\n                    translation_domain=DOMAIN,\n                    translation_key="entity_not_found",\n                    translation_placeholders={"entity_id": entity_id},\n                )\n            if not (\n                speaker\n                := self.config_entry.runtime_data.unique_id_speaker_mappings.get(\n                    entity_reg_entry.unique_id\n                )\n            ):\n                raise HomeAssistantError(\n                    translation_domain=DOMAIN,\n                    translation_key="speaker_not_found",\n                    translation_placeholders={"entity_id": entity_id},\n                )\n\n            speakers.append(speaker)\n\n        await SonosSpeaker.join_multi(\n            self.hass, self.config_entry, self.speaker, speakers\n        )\n\n    async def async_unjoin_player(self) -> None:\n        """Remove this player from any group.\n\n        Coalesces all calls within UNJOIN_SERVICE_TIMEOUT to allow use of SonosSpeaker.unjoin_multi()\n        which optimizes the order in which speakers are removed from their groups.\n        Removing coordinators last better preserves playqueues on the speakers.\n        """\n        sonos_data = self.config_entry.runtime_data\n        household_id = self.speaker.household_id\n\n        async def async_process_unjoin(now: datetime.datetime) -> None:\n            """Process the unjoin with all remove requests within the coalescing period."""\n            unjoin_data = sonos_data.unjoin_data.pop(household_id)\n            _LOGGER.debug(\n                "Processing unjoins for %s", [x.zone_name for x in unjoin_data.speakers]\n            )\n            await SonosSpeaker.unjoin_multi(\n                self.hass, self.config_entry, unjoin_data.speakers\n            )\n            unjoin_data.event.set()\n\n        if unjoin_data := sonos_data.unjoin_data.get(household_id):\n            unjoin_data.speakers.append(self.speaker)\n        else:\n            unjoin_data = sonos_data.unjoin_data[household_id] = UnjoinData(\n                speakers=[self.speaker]\n            )\n            async_call_later(self.hass, UNJOIN_SERVICE_TIMEOUT, async_process_unjoin)\n\n        _LOGGER.debug("Requesting unjoin for %s", self.speaker.zone_name)\n        await unjoin_data.event.wait()\n',
            'tests/components/sonos/test_media_player.py': '"""Tests for the Sonos Media Player platform."""\n\nfrom typing import Any\nfrom unittest.mock import patch\n\nimport pytest\nfrom soco.data_structures import SearchResult\nfrom sonos_websocket.exception import SonosWebsocketError\nfrom syrupy.assertion import SnapshotAssertion\n\nfrom homeassistant.components.media_player import (\n    ATTR_INPUT_SOURCE,\n    ATTR_INPUT_SOURCE_LIST,\n    ATTR_MEDIA_ANNOUNCE,\n    ATTR_MEDIA_CONTENT_ID,\n    ATTR_MEDIA_CONTENT_TYPE,\n    ATTR_MEDIA_ENQUEUE,\n    ATTR_MEDIA_EXTRA,\n    ATTR_MEDIA_REPEAT,\n    ATTR_MEDIA_SHUFFLE,\n    ATTR_MEDIA_VOLUME_LEVEL,\n    DOMAIN as MP_DOMAIN,\n    SERVICE_CLEAR_PLAYLIST,\n    SERVICE_PLAY_MEDIA,\n    SERVICE_SELECT_SOURCE,\n    MediaPlayerEnqueue,\n    RepeatMode,\n)\nfrom homeassistant.components.sonos.const import (\n    DOMAIN,\n    MEDIA_TYPE_DIRECTORY,\n    SOURCE_LINEIN,\n    SOURCE_TV,\n)\nfrom homeassistant.components.sonos.media_player import (\n    LONG_SERVICE_TIMEOUT,\n    VOLUME_INCREMENT,\n)\nfrom homeassistant.components.sonos.services import (\n    ATTR_ALARM_ID,\n    ATTR_ENABLED,\n    ATTR_INCLUDE_LINKED_ZONES,\n    ATTR_VOLUME,\n    SERVICE_GET_QUEUE,\n    SERVICE_RESTORE,\n    SERVICE_SNAPSHOT,\n    SERVICE_UPDATE_ALARM,\n)\nfrom homeassistant.const import (\n    ATTR_ENTITY_ID,\n    ATTR_TIME,\n    SERVICE_MEDIA_NEXT_TRACK,\n    SERVICE_MEDIA_PAUSE,\n    SERVICE_MEDIA_PLAY,\n    SERVICE_MEDIA_PREVIOUS_TRACK,\n    SERVICE_MEDIA_STOP,\n    SERVICE_REPEAT_SET,\n    SERVICE_SHUFFLE_SET,\n    SERVICE_VOLUME_DOWN,\n    SERVICE_VOLUME_SET,\n    SERVICE_VOLUME_UP,\n)\nfrom homeassistant.core import HomeAssistant\nfrom homeassistant.exceptions import HomeAssistantError, ServiceValidationError\nfrom homeassistant.helpers import area_registry as ar, entity_registry as er\nfrom homeassistant.helpers.device_registry import (\n    CONNECTION_NETWORK_MAC,\n    CONNECTION_UPNP,\n    DeviceRegistry,\n)\nfrom homeassistant.setup import async_setup_component\n\nfrom .conftest import MockMusicServiceItem, MockSoCo, SoCoMockFactory, SonosMockEvent\n\n\nasync def test_device_registry(\n    hass: HomeAssistant, device_registry: DeviceRegistry, async_autosetup_sonos, soco\n) -> None:\n    """Test sonos device registered in the device registry."""\n    reg_device = device_registry.async_get_device(\n        identifiers={("sonos", "RINCON_test")}\n    )\n    assert reg_device is not None\n    assert reg_device.model == "Model Name"\n    assert reg_device.model_id == "S12"\n    assert reg_device.sw_version == "13.1"\n    assert reg_device.connections == {\n        (CONNECTION_NETWORK_MAC, "00:11:22:33:44:55"),\n        (CONNECTION_UPNP, "uuid:RINCON_test"),\n    }\n    assert reg_device.manufacturer == "Sonos"\n    assert reg_device.name == "Zone A"\n    # Default device provides battery info, area should not be suggested\n    assert reg_device.area_id is None\n\n\nasync def test_device_registry_not_portable(\n    hass: HomeAssistant,\n    area_registry: ar.AreaRegistry,\n    device_registry: DeviceRegistry,\n    async_setup_sonos,\n    soco,\n) -> None:\n    """Test non-portable sonos device registered in the device registry to ensure area suggested."""\n    soco.get_battery_info.return_value = {}\n    await async_setup_sonos()\n\n    reg_device = device_registry.async_get_device(\n        identifiers={("sonos", "RINCON_test")}\n    )\n    assert reg_device is not None\n    assert reg_device.area_id == area_registry.async_get_area_by_name("Zone A").id\n\n\nasync def test_entity_basic(\n    hass: HomeAssistant,\n    async_autosetup_sonos,\n    discover,\n    entity_registry: er.EntityRegistry,\n    snapshot: SnapshotAssertion,\n) -> None:\n    """Test basic state and attributes."""\n    entity_id = "media_player.zone_a"\n    entity_entry = entity_registry.async_get(entity_id)\n    assert entity_entry == snapshot(name=f"{entity_entry.entity_id}-entry")\n    state = hass.states.get(entity_entry.entity_id)\n    assert state == snapshot(name=f"{entity_entry.entity_id}-state")\n\n\n@pytest.mark.parametrize(\n    ("media_content_type", "media_content_id", "enqueue", "test_result"),\n    [\n        (\n            "artist",\n            "A:ALBUMARTIST/Beatles",\n            MediaPlayerEnqueue.REPLACE,\n            {\n                "title": "All",\n                "item_id": "A:ALBUMARTIST/Beatles/",\n                "clear_queue": 1,\n                "position": None,\n                "play": 1,\n                "play_pos": 0,\n            },\n        ),\n        (\n            "genre",\n            "A:GENRE/Classic%20Rock",\n            MediaPlayerEnqueue.ADD,\n            {\n                "title": "All",\n                "item_id": "A:GENRE/Classic%20Rock/",\n                "clear_queue": 0,\n                "position": None,\n                "play": 0,\n                "play_pos": 0,\n            },\n        ),\n        (\n            "album",\n            "A:ALBUM/Abbey%20Road",\n            MediaPlayerEnqueue.NEXT,\n            {\n                "title": "Abbey Road",\n                "item_id": "A:ALBUM/Abbey%20Road",\n                "clear_queue": 0,\n                "position": 1,\n                "play": 0,\n                "play_pos": 0,\n            },\n        ),\n        (\n            "composer",\n            "A:COMPOSER/Carlos%20Santana",\n            MediaPlayerEnqueue.PLAY,\n            {\n                "title": "All",\n                "item_id": "A:COMPOSER/Carlos%20Santana/",\n                "clear_queue": 0,\n                "position": 1,\n                "play": 1,\n                "play_pos": 9,\n            },\n        ),\n        (\n            "artist",\n            "A:ALBUMARTIST/Beatles/Abbey%20Road",\n            MediaPlayerEnqueue.REPLACE,\n            {\n                "title": "Abbey Road",\n                "item_id": "A:ALBUMARTIST/Beatles/Abbey%20Road",\n                "clear_queue": 1,\n                "position": None,\n                "play": 1,\n                "play_pos": 0,\n            },\n        ),\n        (\n            MEDIA_TYPE_DIRECTORY,\n            "S://192.168.1.1/music/elton%20john",\n            MediaPlayerEnqueue.REPLACE,\n            {\n                "title": None,\n                "item_id": "S://192.168.1.1/music/elton%20john",\n                "clear_queue": 1,\n                "position": None,\n                "play": 1,\n                "play_pos": 0,\n            },\n        ),\n    ],\n)\nasync def test_play_media_library(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    media_content_type,\n    media_content_id,\n    enqueue,\n    test_result,\n) -> None:\n    """Test playing local library with a variety of options."""\n    sock_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: media_content_type,\n            ATTR_MEDIA_CONTENT_ID: media_content_id,\n            ATTR_MEDIA_ENQUEUE: enqueue,\n        },\n        blocking=True,\n    )\n    assert sock_mock.clear_queue.call_count == test_result["clear_queue"]\n    assert sock_mock.add_to_queue.call_count == 1\n    assert (\n        sock_mock.add_to_queue.call_args_list[0].args[0].title == test_result["title"]\n    )\n    assert (\n        sock_mock.add_to_queue.call_args_list[0].args[0].item_id\n        == test_result["item_id"]\n    )\n    if test_result["position"] is not None:\n        assert (\n            sock_mock.add_to_queue.call_args_list[0].kwargs["position"]\n            == test_result["position"]\n        )\n    else:\n        assert "position" not in sock_mock.add_to_queue.call_args_list[0].kwargs\n    assert (\n        sock_mock.add_to_queue.call_args_list[0].kwargs["timeout"]\n        == LONG_SERVICE_TIMEOUT\n    )\n    assert sock_mock.play_from_queue.call_count == test_result["play"]\n    if test_result["play"] != 0:\n        assert (\n            sock_mock.play_from_queue.call_args_list[0].args[0]\n            == test_result["play_pos"]\n        )\n\n\n@pytest.mark.parametrize(\n    ("media_content_type", "media_content_id", "message"),\n    [\n        (\n            "artist",\n            "A:ALBUM/UnknowAlbum",\n            "Could not find media in library: A:ALBUM/UnknowAlbum",\n        ),\n        (\n            "UnknownContent",\n            "A:ALBUM/UnknowAlbum",\n            "Sonos does not support media content type: UnknownContent",\n        ),\n        (\n            MEDIA_TYPE_DIRECTORY,\n            "S://192.168.1.1/music/error",\n            "Could not find media in library: S://192.168.1.1/music/error",\n        ),\n    ],\n)\nasync def test_play_media_library_content_error(\n    hass: HomeAssistant,\n    async_autosetup_sonos,\n    media_content_type,\n    media_content_id,\n    message,\n) -> None:\n    """Test playing local library errors on content and content type."""\n    with pytest.raises(\n        ServiceValidationError,\n        match=message,\n    ):\n        await hass.services.async_call(\n            MP_DOMAIN,\n            SERVICE_PLAY_MEDIA,\n            {\n                ATTR_ENTITY_ID: "media_player.zone_a",\n                ATTR_MEDIA_CONTENT_TYPE: media_content_type,\n                ATTR_MEDIA_CONTENT_ID: media_content_id,\n            },\n            blocking=True,\n        )\n\n\n_track_url = "S://192.168.42.100/music/iTunes/The%20Beatles/A%20Hard%20Day%2fs%I%20Should%20Have%20Known%20Better.mp3"\n\n\nasync def test_play_media_lib_track_play(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n) -> None:\n    """Tests playing media track with enqueue mode play."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "track",\n            ATTR_MEDIA_CONTENT_ID: _track_url,\n            ATTR_MEDIA_ENQUEUE: MediaPlayerEnqueue.PLAY,\n        },\n        blocking=True,\n    )\n    assert soco_mock.add_uri_to_queue.call_count == 1\n    assert soco_mock.add_uri_to_queue.call_args_list[0].args[0] == _track_url\n    assert soco_mock.add_uri_to_queue.call_args_list[0].kwargs["position"] == 1\n    assert (\n        soco_mock.add_uri_to_queue.call_args_list[0].kwargs["timeout"]\n        == LONG_SERVICE_TIMEOUT\n    )\n    assert soco_mock.play_from_queue.call_count == 1\n    assert soco_mock.play_from_queue.call_args_list[0].args[0] == 9\n\n\nasync def test_play_media_lib_track_next(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n) -> None:\n    """Tests playing media track with enqueue mode next."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "track",\n            ATTR_MEDIA_CONTENT_ID: _track_url,\n            ATTR_MEDIA_ENQUEUE: MediaPlayerEnqueue.NEXT,\n        },\n        blocking=True,\n    )\n    assert soco_mock.add_uri_to_queue.call_count == 1\n    assert soco_mock.add_uri_to_queue.call_args_list[0].args[0] == _track_url\n    assert soco_mock.add_uri_to_queue.call_args_list[0].kwargs["position"] == 1\n    assert (\n        soco_mock.add_uri_to_queue.call_args_list[0].kwargs["timeout"]\n        == LONG_SERVICE_TIMEOUT\n    )\n    assert soco_mock.play_from_queue.call_count == 0\n\n\nasync def test_play_media_lib_track_replace(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n) -> None:\n    """Tests playing media track with enqueue mode replace."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "track",\n            ATTR_MEDIA_CONTENT_ID: _track_url,\n            ATTR_MEDIA_ENQUEUE: MediaPlayerEnqueue.REPLACE,\n        },\n        blocking=True,\n    )\n    assert soco_mock.play_uri.call_count == 1\n    assert soco_mock.play_uri.call_args_list[0].args[0] == _track_url\n    assert soco_mock.play_uri.call_args_list[0].kwargs["force_radio"] is False\n\n\nasync def test_play_media_lib_track_add(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n) -> None:\n    """Tests playing media track with enqueue mode add."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "track",\n            ATTR_MEDIA_CONTENT_ID: _track_url,\n            ATTR_MEDIA_ENQUEUE: MediaPlayerEnqueue.ADD,\n        },\n        blocking=True,\n    )\n    assert soco_mock.add_uri_to_queue.call_count == 1\n    assert soco_mock.add_uri_to_queue.call_args_list[0].args[0] == _track_url\n    assert (\n        soco_mock.add_uri_to_queue.call_args_list[0].kwargs["timeout"]\n        == LONG_SERVICE_TIMEOUT\n    )\n    assert soco_mock.play_from_queue.call_count == 0\n\n\n_share_link: str = "spotify:playlist:abcdefghij0123456789XY"\n\n\nasync def test_play_media_share_link_add(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    soco_sharelink,\n) -> None:\n    """Tests playing a share link with enqueue option add."""\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "playlist",\n            ATTR_MEDIA_CONTENT_ID: _share_link,\n            ATTR_MEDIA_ENQUEUE: MediaPlayerEnqueue.ADD,\n        },\n        blocking=True,\n    )\n    assert soco_sharelink.add_share_link_to_queue.call_count == 1\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].args[0] == _share_link\n    )\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].kwargs["timeout"]\n        == LONG_SERVICE_TIMEOUT\n    )\n\n\nasync def test_play_media_share_link_next(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    soco_sharelink,\n) -> None:\n    """Tests playing a share link with enqueue option next."""\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "playlist",\n            ATTR_MEDIA_CONTENT_ID: _share_link,\n            ATTR_MEDIA_ENQUEUE: MediaPlayerEnqueue.NEXT,\n        },\n        blocking=True,\n    )\n    assert soco_sharelink.add_share_link_to_queue.call_count == 1\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].args[0] == _share_link\n    )\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].kwargs["timeout"]\n        == LONG_SERVICE_TIMEOUT\n    )\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].kwargs["position"] == 1\n    )\n\n\nasync def test_play_media_share_link_play(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    soco_sharelink,\n) -> None:\n    """Tests playing a share link with enqueue option play."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "playlist",\n            ATTR_MEDIA_CONTENT_ID: _share_link,\n            ATTR_MEDIA_ENQUEUE: MediaPlayerEnqueue.PLAY,\n        },\n        blocking=True,\n    )\n    assert soco_sharelink.add_share_link_to_queue.call_count == 1\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].args[0] == _share_link\n    )\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].kwargs["timeout"]\n        == LONG_SERVICE_TIMEOUT\n    )\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].kwargs["position"] == 1\n    )\n    assert soco_mock.play_from_queue.call_count == 1\n    soco_mock.play_from_queue.assert_called_with(9)\n\n\nasync def test_play_media_share_link_replace(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    soco_sharelink,\n) -> None:\n    """Tests playing a share link with enqueue option replace."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "playlist",\n            ATTR_MEDIA_CONTENT_ID: _share_link,\n            ATTR_MEDIA_ENQUEUE: MediaPlayerEnqueue.REPLACE,\n        },\n        blocking=True,\n    )\n    assert soco_mock.clear_queue.call_count == 1\n    assert soco_sharelink.add_share_link_to_queue.call_count == 1\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].args[0] == _share_link\n    )\n    assert (\n        soco_sharelink.add_share_link_to_queue.call_args_list[0].kwargs["timeout"]\n        == LONG_SERVICE_TIMEOUT\n    )\n    assert soco_mock.play_from_queue.call_count == 1\n    soco_mock.play_from_queue.assert_called_with(0)\n\n\n_mock_playlists = [\n    MockMusicServiceItem(\n        "playlist1",\n        "S://192.168.1.68/music/iTunes/iTunes%20Music%20Library.xml#GUID_1",\n        "A:PLAYLISTS",\n        "object.container.playlistContainer",\n    ),\n    MockMusicServiceItem(\n        "playlist2",\n        "S://192.168.1.68/music/iTunes/iTunes%20Music%20Library.xml#GUID_2",\n        "A:PLAYLISTS",\n        "object.container.playlistContainer",\n    ),\n]\n\n\n@pytest.mark.parametrize(\n    ("media_content_id", "expected_item_id"),\n    [\n        (\n            _mock_playlists[0].item_id,\n            _mock_playlists[0].item_id,\n        ),\n        (\n            f"S:{_mock_playlists[1].title}",\n            _mock_playlists[1].item_id,\n        ),\n    ],\n)\nasync def test_play_media_music_library_playlist(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    discover,\n    media_content_id,\n    expected_item_id,\n) -> None:\n    """Test that playlists can be found by id or title."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    soco_mock.music_library.get_playlists.return_value = _mock_playlists\n\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "playlist",\n            ATTR_MEDIA_CONTENT_ID: media_content_id,\n        },\n        blocking=True,\n    )\n\n    assert soco_mock.clear_queue.call_count == 1\n    assert soco_mock.add_to_queue.call_count == 1\n    assert soco_mock.add_to_queue.call_args_list[0].args[0].item_id == expected_item_id\n    assert soco_mock.play_from_queue.call_count == 1\n\n\nasync def test_play_media_music_library_playlist_dne(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    caplog: pytest.LogCaptureFixture,\n) -> None:\n    """Test error handling when attempting to play a non-existent playlist ."""\n    media_content_id = "S:nonexistent"\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    soco_mock.music_library.get_playlists.return_value = _mock_playlists\n\n    with pytest.raises(\n        ServiceValidationError,\n        match=f"Could not find Sonos playlist: {media_content_id}",\n    ):\n        await hass.services.async_call(\n            MP_DOMAIN,\n            SERVICE_PLAY_MEDIA,\n            {\n                ATTR_ENTITY_ID: "media_player.zone_a",\n                ATTR_MEDIA_CONTENT_TYPE: "playlist",\n                ATTR_MEDIA_CONTENT_ID: media_content_id,\n            },\n            blocking=True,\n        )\n    assert soco_mock.play_uri.call_count == 0\n\n\nasync def test_play_sonos_playlist(\n    hass: HomeAssistant,\n    async_autosetup_sonos,\n    soco: MockSoCo,\n    sonos_playlists: SearchResult,\n) -> None:\n    """Test that sonos playlists can be played."""\n\n    # Test a successful call\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "playlist",\n            ATTR_MEDIA_CONTENT_ID: "sample playlist",\n        },\n        blocking=True,\n    )\n    assert soco.clear_queue.call_count == 1\n    assert soco.add_to_queue.call_count == 1\n    soco.add_to_queue.asset_called_with(\n        sonos_playlists[0], timeout=LONG_SERVICE_TIMEOUT\n    )\n\n    # Test playing a non-existent playlist\n    soco.clear_queue.reset_mock()\n    soco.add_to_queue.reset_mock()\n    media_content_id: str = "bad playlist"\n    with pytest.raises(\n        ServiceValidationError,\n        match=f"Could not find Sonos playlist: {media_content_id}",\n    ):\n        await hass.services.async_call(\n            MP_DOMAIN,\n            SERVICE_PLAY_MEDIA,\n            {\n                ATTR_ENTITY_ID: "media_player.zone_a",\n                ATTR_MEDIA_CONTENT_TYPE: "playlist",\n                ATTR_MEDIA_CONTENT_ID: media_content_id,\n            },\n            blocking=True,\n        )\n    assert soco.clear_queue.call_count == 0\n    assert soco.add_to_queue.call_count == 0\n\n\n@pytest.mark.parametrize(\n    ("source", "result"),\n    [\n        (\n            SOURCE_LINEIN,\n            {\n                "switch_to_line_in": 1,\n            },\n        ),\n        (\n            SOURCE_TV,\n            {\n                "switch_to_tv": 1,\n            },\n        ),\n    ],\n)\nasync def test_select_source_line_in_tv(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    source: str,\n    result: dict[str, Any],\n) -> None:\n    """Test the select_source method with a variety of inputs."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_SELECT_SOURCE,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_INPUT_SOURCE: source,\n        },\n        blocking=True,\n    )\n    assert soco_mock.switch_to_line_in.call_count == result.get("switch_to_line_in", 0)\n    assert soco_mock.switch_to_tv.call_count == result.get("switch_to_tv", 0)\n\n\n@pytest.mark.parametrize(\n    ("source", "result"),\n    [\n        (\n            "James Taylor Radio",\n            {\n                "play_uri": 1,\n                "play_uri_uri": "x-sonosapi-radio:ST%3aetc",\n                "play_uri_title": "James Taylor Radio",\n                "play_uri_meta": \'<DIDL-Lite xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:upnp="urn:schemas-upnp-org:metadata-1-0/upnp/" xmlns:r="urn:schemas-rinconnetworks-com:metadata-1-0/" xmlns="urn:schemas-upnp-org:metadata-1-0/DIDL-Lite/"><item id="100c2068ST%3a1683194971234567890" parentID="10fe2064myStations" restricted="true"><dc:title>James Taylor Radio</dc:title><upnp:class>object.item.audioItem.audioBroadcast.#station</upnp:class><desc id="cdudn" nameSpace="urn:schemas-rinconnetworks-com:metadata-1-0/">SA_RINCON60423_X_#Svc60423-99999999-Token</desc></item></DIDL-Lite>\',\n            },\n        ),\n        (\n            "66 - Watercolors",\n            {\n                "play_uri": 1,\n                "play_uri_uri": "x-sonosapi-hls:Api%3atune%3aliveAudio%3ajazzcafe%3aetc",\n                "play_uri_title": "66 - Watercolors",\n                "play_uri_meta": \'<DIDL-Lite xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:upnp="urn:schemas-upnp-org:metadata-1-0/upnp/" xmlns:r="urn:schemas-rinconnetworks-com:metadata-1-0/" xmlns="urn:schemas-upnp-org:metadata-1-0/DIDL-Lite/"><item id="10090120Api%3atune%3aliveAudio%3ajazzcafe%3ae4b5402c-9999-9999-9999-4bc8e2cdccce" parentID="10086064live%3f93b0b9cb-9999-9999-9999-bcf75971fcfe" restricted="false"><dc:title>66 - Watercolors</dc:title><upnp:class>object.item.audioItem.audioBroadcast</upnp:class><desc id="cdudn" nameSpace="urn:schemas-rinconnetworks-com:metadata-1-0/">SA_RINCON9479_X_#Svc9479-99999999-Token</desc></item></DIDL-Lite>\',\n            },\n        ),\n        (\n            "American Tall Tales",\n            {\n                "play_uri": 1,\n                "play_uri_uri": "x-rincon-cpcontainer:101340c8reftitle%C9F27_com?sid=239&flags=16584&sn=5",\n                "play_uri_title": "American Tall Tales",\n                "play_uri_meta": \'<DIDL-Lite xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:upnp="urn:schemas-upnp-org:metadata-1-0/upnp/" xmlns:r="urn:schemas-rinconnetworks-com:metadata-1-0/" xmlns="urn:schemas-upnp-org:metadata-1-0/DIDL-Lite/"><item id="101340c8reftitleC9F27_com" parentID="101340c8reftitleC9F27_com" restricted="true"><dc:title>American Tall Tales</dc:title><upnp:class>object.item.audioItem.audioBook</upnp:class><desc id="cdudn" nameSpace="urn:schemas-rinconnetworks-com:metadata-1-0/">SA_RINCON61191_X_#Svc6-0-Token</desc></item></DIDL-Lite>\',\n            },\n        ),\n    ],\n)\nasync def test_select_source_play_uri(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    source: str,\n    result: dict[str, Any],\n) -> None:\n    """Test the select_source method with a variety of inputs."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_SELECT_SOURCE,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_INPUT_SOURCE: source,\n        },\n        blocking=True,\n    )\n    assert soco_mock.play_uri.call_count == result.get("play_uri")\n    soco_mock.play_uri.assert_called_with(\n        result.get("play_uri_uri"),\n        title=result.get("play_uri_title"),\n        meta=result.get("play_uri_meta"),\n        timeout=LONG_SERVICE_TIMEOUT,\n    )\n\n\n@pytest.mark.parametrize(\n    ("source", "result"),\n    [\n        (\n            "1984",\n            {\n                "add_to_queue": 1,\n                "add_to_queue_item_id": "A:ALBUMARTIST/Aerosmith/1984",\n                "clear_queue": 1,\n                "play_from_queue": 1,\n            },\n        ),\n    ],\n)\nasync def test_select_source_play_queue(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n    source: str,\n    result: dict[str, Any],\n) -> None:\n    """Test the select_source method with a variety of inputs."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_SELECT_SOURCE,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_INPUT_SOURCE: source,\n        },\n        blocking=True,\n    )\n    assert soco_mock.clear_queue.call_count == result.get("clear_queue")\n    assert soco_mock.add_to_queue.call_count == result.get("add_to_queue")\n    assert soco_mock.add_to_queue.call_args_list[0].args[0].item_id == result.get(\n        "add_to_queue_item_id"\n    )\n    assert (\n        soco_mock.add_to_queue.call_args_list[0].kwargs["timeout"]\n        == LONG_SERVICE_TIMEOUT\n    )\n    assert soco_mock.play_from_queue.call_count == result.get("play_from_queue")\n    soco_mock.play_from_queue.assert_called_with(0)\n\n\nasync def test_select_source_error(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n) -> None:\n    """Test the select_source method with a variety of inputs."""\n    with pytest.raises(ServiceValidationError) as sve:\n        await hass.services.async_call(\n            MP_DOMAIN,\n            SERVICE_SELECT_SOURCE,\n            {\n                ATTR_ENTITY_ID: "media_player.zone_a",\n                ATTR_INPUT_SOURCE: "invalid_source",\n            },\n            blocking=True,\n        )\n    assert "invalid_source" in str(sve.value)\n    assert "Could not find a Sonos favorite" in str(sve.value)\n\n\nasync def test_shuffle_set(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n) -> None:\n    """Test the set shuffle method."""\n    assert soco.play_mode == "NORMAL"\n\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_SHUFFLE_SET,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_SHUFFLE: True,\n        },\n        blocking=True,\n    )\n    assert soco.play_mode == "SHUFFLE_NOREPEAT"\n\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_SHUFFLE_SET,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_SHUFFLE: False,\n        },\n        blocking=True,\n    )\n    assert soco.play_mode == "NORMAL"\n\n\nasync def test_shuffle_get(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n    no_media_event: SonosMockEvent,\n) -> None:\n    """Test the get shuffle attribute by simulating a Sonos Event."""\n    subscription = soco.avTransport.subscribe.return_value\n    sub_callback = subscription.callback\n\n    state = hass.states.get("media_player.zone_a")\n    assert state.attributes[ATTR_MEDIA_SHUFFLE] is False\n\n    no_media_event.variables["current_play_mode"] = "SHUFFLE_NOREPEAT"\n    sub_callback(no_media_event)\n    await hass.async_block_till_done(wait_background_tasks=True)\n    state = hass.states.get("media_player.zone_a")\n    assert state.attributes[ATTR_MEDIA_SHUFFLE] is True\n\n    # The integration keeps a copy of the last event to check for\n    # changes, so we create a new event.\n    no_media_event = SonosMockEvent(\n        soco, soco.avTransport, no_media_event.variables.copy()\n    )\n    no_media_event.variables["current_play_mode"] = "NORMAL"\n    sub_callback(no_media_event)\n    await hass.async_block_till_done(wait_background_tasks=True)\n    state = hass.states.get("media_player.zone_a")\n    assert state.attributes[ATTR_MEDIA_SHUFFLE] is False\n\n\nasync def test_repeat_set(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n) -> None:\n    """Test the set repeat method."""\n    assert soco.play_mode == "NORMAL"\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_REPEAT_SET,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_REPEAT: RepeatMode.ALL,\n        },\n        blocking=True,\n    )\n    assert soco.play_mode == "REPEAT_ALL"\n\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_REPEAT_SET,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_REPEAT: RepeatMode.ONE,\n        },\n        blocking=True,\n    )\n    assert soco.play_mode == "REPEAT_ONE"\n\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_REPEAT_SET,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_REPEAT: RepeatMode.OFF,\n        },\n        blocking=True,\n    )\n    assert soco.play_mode == "NORMAL"\n\n\nasync def test_repeat_get(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n    no_media_event: SonosMockEvent,\n) -> None:\n    """Test the get repeat attribute by simulating a Sonos Event."""\n    subscription = soco.avTransport.subscribe.return_value\n    sub_callback = subscription.callback\n\n    state = hass.states.get("media_player.zone_a")\n    assert state.attributes[ATTR_MEDIA_REPEAT] == RepeatMode.OFF\n\n    no_media_event.variables["current_play_mode"] = "REPEAT_ALL"\n    sub_callback(no_media_event)\n    await hass.async_block_till_done(wait_background_tasks=True)\n    state = hass.states.get("media_player.zone_a")\n    assert state.attributes[ATTR_MEDIA_REPEAT] == RepeatMode.ALL\n\n    no_media_event = SonosMockEvent(\n        soco, soco.avTransport, no_media_event.variables.copy()\n    )\n    no_media_event.variables["current_play_mode"] = "REPEAT_ONE"\n    sub_callback(no_media_event)\n    await hass.async_block_till_done(wait_background_tasks=True)\n    state = hass.states.get("media_player.zone_a")\n    assert state.attributes[ATTR_MEDIA_REPEAT] == RepeatMode.ONE\n\n    no_media_event = SonosMockEvent(\n        soco, soco.avTransport, no_media_event.variables.copy()\n    )\n    no_media_event.variables["current_play_mode"] = "NORMAL"\n    sub_callback(no_media_event)\n    await hass.async_block_till_done(wait_background_tasks=True)\n    state = hass.states.get("media_player.zone_a")\n    assert state.attributes[ATTR_MEDIA_REPEAT] == RepeatMode.OFF\n\n\nasync def test_play_media_favorite_item_id(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n    async_autosetup_sonos,\n) -> None:\n    """Test playing media with a favorite item id."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "favorite_item_id",\n            ATTR_MEDIA_CONTENT_ID: "FV:2/4",\n        },\n        blocking=True,\n    )\n    assert soco_mock.play_uri.call_count == 1\n    assert (\n        soco_mock.play_uri.call_args_list[0].args[0]\n        == "x-sonosapi-hls:Api%3atune%3aliveAudio%3ajazzcafe%3aetc"\n    )\n    assert (\n        soco_mock.play_uri.call_args_list[0].kwargs["timeout"] == LONG_SERVICE_TIMEOUT\n    )\n    assert soco_mock.play_uri.call_args_list[0].kwargs["title"] == "66 - Watercolors"\n\n    # Test exception handling with an invalid id.\n    with pytest.raises(ValueError) as sve:\n        await hass.services.async_call(\n            MP_DOMAIN,\n            SERVICE_PLAY_MEDIA,\n            {\n                ATTR_ENTITY_ID: "media_player.zone_a",\n                ATTR_MEDIA_CONTENT_TYPE: "favorite_item_id",\n                ATTR_MEDIA_CONTENT_ID: "UNKNOWN_ID",\n            },\n            blocking=True,\n        )\n    assert "UNKNOWN_ID" in str(sve.value)\n\n\nasync def _setup_hass(hass: HomeAssistant):\n    await async_setup_component(\n        hass,\n        DOMAIN,\n        {\n            "sonos": {\n                "media_player": {\n                    "interface_addr": "127.0.0.1",\n                    "hosts": ["10.10.10.1", "10.10.10.2"],\n                }\n            }\n        },\n    )\n    await hass.async_block_till_done()\n\n\nasync def test_service_snapshot_restore(\n    hass: HomeAssistant,\n    soco_factory: SoCoMockFactory,\n) -> None:\n    """Test the snapshot and restore services."""\n    soco_factory.cache_mock(MockSoCo(), "10.10.10.1", "Living Room")\n    soco_factory.cache_mock(MockSoCo(), "10.10.10.2", "Bedroom")\n    await _setup_hass(hass)\n    with patch(\n        "homeassistant.components.sonos.speaker.Snapshot.snapshot"\n    ) as mock_snapshot:\n        await hass.services.async_call(\n            DOMAIN,\n            SERVICE_SNAPSHOT,\n            {\n                ATTR_ENTITY_ID: ["media_player.living_room", "media_player.bedroom"],\n            },\n            blocking=True,\n        )\n    assert mock_snapshot.call_count == 2\n\n    with patch(\n        "homeassistant.components.sonos.speaker.Snapshot.restore"\n    ) as mock_restore:\n        await hass.services.async_call(\n            DOMAIN,\n            SERVICE_RESTORE,\n            {\n                ATTR_ENTITY_ID: ["media_player.living_room", "media_player.bedroom"],\n            },\n            blocking=True,\n        )\n    assert mock_restore.call_count == 2\n\n\nasync def test_volume(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n) -> None:\n    """Test the media player volume services."""\n    initial_volume = soco.volume\n\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_VOLUME_UP,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n        },\n        blocking=True,\n    )\n    assert soco.volume == initial_volume + VOLUME_INCREMENT\n\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_VOLUME_DOWN,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n        },\n        blocking=True,\n    )\n    assert soco.volume == initial_volume\n\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_VOLUME_SET,\n        {ATTR_ENTITY_ID: "media_player.zone_a", ATTR_MEDIA_VOLUME_LEVEL: 0.57},\n        blocking=True,\n    )\n    # SoCo uses 0..100 for its range.\n    assert soco.volume == 57\n\n\n@pytest.mark.parametrize(\n    ("service", "client_call"),\n    [\n        (SERVICE_MEDIA_PLAY, "play"),\n        (SERVICE_MEDIA_PAUSE, "pause"),\n        (SERVICE_MEDIA_STOP, "stop"),\n        (SERVICE_MEDIA_NEXT_TRACK, "next"),\n        (SERVICE_MEDIA_PREVIOUS_TRACK, "previous"),\n        (SERVICE_CLEAR_PLAYLIST, "clear_queue"),\n    ],\n)\nasync def test_media_transport(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n    service: str,\n    client_call: str,\n) -> None:\n    """Test the media player transport services."""\n    await hass.services.async_call(\n        MP_DOMAIN,\n        service,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n        },\n        blocking=True,\n    )\n    assert getattr(soco, client_call).call_count == 1\n\n\nasync def test_play_media_announce(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n    sonos_websocket,\n) -> None:\n    """Test playing media with the announce."""\n    content_id: str = "http://10.0.0.1:8123/local/sounds/doorbell.mp3"\n    volume: float = 0.30\n\n    # Test the success path\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "music",\n            ATTR_MEDIA_CONTENT_ID: content_id,\n            ATTR_MEDIA_ANNOUNCE: True,\n            ATTR_MEDIA_EXTRA: {"volume": volume},\n        },\n        blocking=True,\n    )\n    assert sonos_websocket.play_clip.call_count == 1\n    sonos_websocket.play_clip.assert_called_with(content_id, volume=volume)\n\n    # Test receiving a websocket exception\n    sonos_websocket.play_clip.reset_mock()\n    sonos_websocket.play_clip.side_effect = SonosWebsocketError("Error Message")\n    with pytest.raises(\n        HomeAssistantError, match="Error when calling Sonos websocket: Error Message"\n    ):\n        await hass.services.async_call(\n            MP_DOMAIN,\n            SERVICE_PLAY_MEDIA,\n            {\n                ATTR_ENTITY_ID: "media_player.zone_a",\n                ATTR_MEDIA_CONTENT_TYPE: "music",\n                ATTR_MEDIA_CONTENT_ID: content_id,\n                ATTR_MEDIA_ANNOUNCE: True,\n            },\n            blocking=True,\n        )\n    assert sonos_websocket.play_clip.call_count == 1\n    sonos_websocket.play_clip.assert_called_with(content_id, volume=None)\n\n    # Test receiving a non success result\n    sonos_websocket.play_clip.reset_mock()\n    sonos_websocket.play_clip.side_effect = None\n    retval = {"success": 0}\n    sonos_websocket.play_clip.return_value = [retval, {}]\n    with pytest.raises(\n        HomeAssistantError, match=f"Announcing clip {content_id} failed {retval}"\n    ):\n        await hass.services.async_call(\n            MP_DOMAIN,\n            SERVICE_PLAY_MEDIA,\n            {\n                ATTR_ENTITY_ID: "media_player.zone_a",\n                ATTR_MEDIA_CONTENT_TYPE: "music",\n                ATTR_MEDIA_CONTENT_ID: content_id,\n                ATTR_MEDIA_ANNOUNCE: True,\n            },\n            blocking=True,\n        )\n    assert sonos_websocket.play_clip.call_count == 1\n\n    # Test speakers that do not support announce. This\n    # will result in playing the clip directly via play_uri\n    sonos_websocket.play_clip.reset_mock()\n    sonos_websocket.play_clip.side_effect = None\n    retval = {"success": 0, "type": "globalError"}\n    sonos_websocket.play_clip.return_value = [retval, {}]\n\n    await hass.services.async_call(\n        MP_DOMAIN,\n        SERVICE_PLAY_MEDIA,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_MEDIA_CONTENT_TYPE: "music",\n            ATTR_MEDIA_CONTENT_ID: content_id,\n            ATTR_MEDIA_ANNOUNCE: True,\n        },\n        blocking=True,\n    )\n    assert sonos_websocket.play_clip.call_count == 1\n    soco.play_uri.assert_called_with(content_id, force_radio=False)\n\n\nasync def test_media_get_queue(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n    soco_factory,\n    snapshot: SnapshotAssertion,\n) -> None:\n    """Test getting the media queue."""\n    soco_mock = soco_factory.mock_list.get("192.168.42.2")\n    result = await hass.services.async_call(\n        DOMAIN,\n        SERVICE_GET_QUEUE,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n        },\n        blocking=True,\n        return_response=True,\n    )\n    soco_mock.get_queue.assert_called_with(max_items=0)\n    assert result == snapshot\n\n\n@pytest.mark.parametrize(\n    ("speaker_model", "source_list"),\n    [\n        ("Sonos Arc Ultra", [SOURCE_TV]),\n        ("Sonos Arc", [SOURCE_TV]),\n        ("Sonos Playbar", [SOURCE_TV]),\n        ("Sonos Connect", [SOURCE_LINEIN]),\n        ("Sonos Play:5", [SOURCE_LINEIN]),\n        ("Sonos Amp", [SOURCE_LINEIN, SOURCE_TV]),\n        ("Sonos Era", None),\n    ],\n    indirect=["speaker_model"],\n)\nasync def test_media_source_list(\n    hass: HomeAssistant,\n    async_autosetup_sonos,\n    speaker_model: str,\n    source_list: list[str] | None,\n) -> None:\n    """Test the mapping between the speaker model name and source_list."""\n    state = hass.states.get("media_player.zone_a")\n    assert state.attributes.get(ATTR_INPUT_SOURCE_LIST) == source_list\n\n\nasync def test_service_update_alarm(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n) -> None:\n    """Test updating an alarm."""\n\n    await hass.services.async_call(\n        DOMAIN,\n        SERVICE_UPDATE_ALARM,\n        {\n            ATTR_ENTITY_ID: "media_player.zone_a",\n            ATTR_ALARM_ID: 14,\n            ATTR_TIME: "07:15:00",\n            ATTR_VOLUME: 0.25,\n            ATTR_INCLUDE_LINKED_ZONES: True,\n            ATTR_ENABLED: True,\n        },\n        blocking=True,\n    )\n\n    assert soco.alarmClock.UpdateAlarm.call_count == 1\n    assert soco.alarmClock.UpdateAlarm.call_args.args[0] == [\n        ("ID", "14"),\n        ("StartLocalTime", "07:15:00"),\n        ("Duration", "02:00:00"),\n        ("Recurrence", "DAILY"),\n        ("Enabled", "1"),\n        ("RoomUUID", "RINCON_test"),\n        ("ProgramURI", "x-rincon-buzzer:0"),\n        ("ProgramMetaData", ""),\n        ("PlayMode", "SHUFFLE_NOREPEAT"),\n        ("Volume", 25),\n        ("IncludeLinkedZones", "1"),\n    ]\n\n\nasync def test_service_update_alarm_dne(\n    hass: HomeAssistant,\n    soco: MockSoCo,\n    async_autosetup_sonos,\n) -> None:\n    """Test updating an alarm that does not exist."""\n\n    with pytest.raises(\n        ServiceValidationError,\n        match="Alarm 99 does not exist and cannot be updated",\n    ):\n        await hass.services.async_call(\n            DOMAIN,\n            SERVICE_UPDATE_ALARM,\n            {\n                ATTR_ENTITY_ID: "media_player.zone_a",\n                ATTR_ALARM_ID: 99,\n                ATTR_TIME: "07:15:00",\n                ATTR_VOLUME: 0.25,\n                ATTR_INCLUDE_LINKED_ZONES: True,\n                ATTR_ENABLED: True,\n            },\n            blocking=True,\n        )\n    assert soco.alarmClock.UpdateAlarm.call_count == 0\n',
        }
